import{c as t,Q as a,j as o,m as i}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"How to Give Claude Perfect Memory (complete guide) — @aiedge_","description":"","frontmatter":{"title":"How to Give Claude Perfect Memory (complete guide) — @aiedge_","author":"aiedge_（@aiedge_）","date":"2026-04-22T00:00:00.000Z","source":"https://x.com/aiedge_/status/2046966170868486512","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-22-@aiedge_-486512.md","filePath":"research/tweets/2026-04-22-@aiedge_-486512.md","lastUpdated":1779894392000}'),r={name:"research/tweets/2026-04-22-@aiedge_-486512.md"};function s(n,e,l,d,h,c){return a(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="how-to-give-claude-perfect-memory-complete-guide-—-aiedge" tabindex="-1">How to Give Claude Perfect Memory (complete guide) — @aiedge_ <a class="header-anchor" href="#how-to-give-claude-perfect-memory-complete-guide-—-aiedge" aria-label="Permalink to &quot;How to Give Claude Perfect Memory (complete guide) — @aiedge_&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/aiedge_/status/2046966170868486512" target="_blank" rel="noreferrer">https://x.com/aiedge_/status/2046966170868486512</a><strong>作者</strong>：aiedge_（@aiedge_） <strong>發布日期</strong>：2026-04-22 <strong>收錄日期</strong>：2026-04-26 <strong>類型</strong>：Twitter Article <strong>統計</strong>：1,518 likes · 189 retweets · 7,588 bookmarks · 1,510,923 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>I don&#39;t care what anyone tells you - by default, Claude&#39;s memory is basically useless.</p><p>It frequently forgets context; you constantly have to re-explain yourself, and even after you do, it still often doesn&#39;t remember.</p><p>I discovered three &quot;layers&quot; of memory systems, and they&#39;ve made Claude significantly more powerful.</p><h4 id="layer-one-basic-memory-beginner" tabindex="-1">Layer one: Basic Memory (Beginner) <a class="header-anchor" href="#layer-one-basic-memory-beginner" aria-label="Permalink to &quot;Layer one: Basic Memory (Beginner)&quot;">​</a></h4><p><strong>1. Memory Editing Tool</strong></p><p>Settings → Memory：管理 Claude 自動累積的記憶（刪除過時/不準確的，手動添加關鍵 context）</p><p><strong>2. Project Instructions</strong></p><p>在 Claude Projects 的 Project Instructions 欄位填入 context。建議：用語音轉文字整理成 Google Doc 再上傳 PDF。</p><p><strong>3. Tell Claude Directly</strong></p><p>直接在對話中告訴 Claude 要記住什麼；也可說「Forget that I mentioned [x]」</p><p><strong>4. Memory Imports &amp; Exports</strong></p><p>Settings → Memory 可 import 來自其他 LLM（ChatGPT 等）的 context。</p><p>→ 這 4 個設定滿足 90%+ 用戶</p><h4 id="layer-two-context-file-system-intermediate" tabindex="-1">Layer two: Context File System (Intermediate) <a class="header-anchor" href="#layer-two-context-file-system-intermediate" aria-label="Permalink to &quot;Layer two: Context File System (Intermediate)&quot;">​</a></h4><p>設置時間：約 60 分鐘。核心概念：將 context 儲存在本機 .MD 檔案，Claude Code/Cowork 自動載入。</p><p><strong>Claude Master Folder 四個 markdown 檔案：</strong></p><ol><li><strong>Instructions.MD</strong> — Claude 的規則和指令</li></ol><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Who you are</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## What you do</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Rules</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## What good outputs look like</span></span></code></pre></div><p>關鍵行：「Update Memory.MD with my preferences over time.」</p><ol start="2"><li><strong>Memory.MD</strong> — Claude 的「大腦」，持續自動更新</li></ol><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Preferences</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Corrections</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Patterns</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Decisions</span></span></code></pre></div><p>當你說「stop using em dashes」時，Claude 會自動更新這個檔案。</p><ol start="3"><li><p><strong>Context.MD</strong> — 特定專案的 context 檔案</p></li><li><p><strong>Archive Copies</strong> — 每週手動備份整個 master folder 到 Claude 無法存取的位置，防止意外覆寫</p></li></ol><p><strong>使用方式</strong>：在 Cowork/Claude Code 中 attach Master Folder → Claude 自動用作 mini memory database，編輯 memory markdown file</p><h4 id="layer-three-ai-second-brain-advanced" tabindex="-1">Layer three: AI Second Brain (Advanced) <a class="header-anchor" href="#layer-three-ai-second-brain-advanced" aria-label="Permalink to &quot;Layer three: AI Second Brain (Advanced)&quot;">​</a></h4><p>（原文截斷，涉及 AI 訓練在所有個人數據上的「自進化第二大腦」概念）</p><h4 id="final-thoughts" tabindex="-1">Final Thoughts <a class="header-anchor" href="#final-thoughts" aria-label="Permalink to &quot;Final Thoughts&quot;">​</a></h4><p>作者每天大量使用 Claude，所有內容為手寫（非 AI 生成），每週發布 2-3 篇 AI 文章。</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：Claude 記憶系統三層架構：Layer 1（原生設定快速修復）→ Layer 2（本機 .MD 檔案作為持久化 context）→ Layer 3（自進化第二大腦），60 分鐘設置的 Context File System 是最高槓桿的中級解決方案。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li>Claude 預設記憶不可用，三層分級解決方案讓 90% 使用者可在 10 分鐘內改善</li><li>Layer 2 的關鍵洞見：Instructions.MD 中的「Update Memory.MD with my preferences over time」一行，讓 Claude 自動維護記憶文件</li><li>Memory.MD 分層（Preferences/Corrections/Patterns/Decisions）是一個實用的 context 組織框架</li><li>Archive 備份策略防止 Claude 自動更新時意外覆寫：每週手動備份到 Claude 無法存取的資料夾</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>Layer 2 設置時間：約 60 分鐘</li><li>Settings → Memory 匯入/匯出支援跨 LLM 遷移</li><li>受益用戶群：文章作者稱滿足 90%+ 用戶</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li>Layer 2 的 Context File System 概念與 cc-workspace 的 CLAUDE.md + Auto Memory 機制高度重疊</li><li>Memory.MD 自動更新機制依賴 Claude 的判斷，可能導致非預期修改（文章本身承認此問題並建議備份）</li><li>Layer 3（AI 第二大腦）的細節在本推文 JSON 中截斷，無法評估</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>7/10</td><td>Instructions.MD + Memory.MD 分層設計可直接應用於 cc-workspace 的 CLAUDE.md 設計改進</td></tr><tr><td>B. 創新性 (20%)</td><td>6/10</td><td>Memory.MD 自動更新機制和 Corrections/Patterns/Decisions 分層是有洞見的設計</td></tr><tr><td>C. 證據品質 (20%)</td><td>5/10</td><td>來自個人日常使用，無量化測量，但操作步驟完整</td></tr><tr><td>D. 技術深度 (15%)</td><td>6/10</td><td>完整設置步驟，包含 Archive 備份策略等細節</td></tr><tr><td>E. 泛化性 (15%)</td><td>8/10</td><td>跨所有 Claude 使用場景通用</td></tr><tr><td><strong>加權總分</strong></td><td><strong>6.55/10</strong></td><td>7×0.3 + 6×0.2 + 5×0.2 + 6×0.15 + 8×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Rule <strong>理由</strong>：Instructions.MD + Memory.MD 分層架構和 Archive 備份策略屬通用記憶管理原則，適合補充到 <code>.claude/rules/context-management.md</code> 作為 Claude 記憶系統最佳實踐</p>`,45)])])}const u=t(r,[["render",s]]);export{g as __pageData,u as default};
